// Evalúa cada respuesta HTTP y clasifica como PASS o FAIL
const results = [];

const checks = [
  {
    id: 'CRIT-01-conversations',
    name: 'CRIT-01 — conversations sin RLS',
    node: 'TEST-CRIT01 — Leer conversations',
    expectEmptyBody: true,
    severity: 'CRITICAL'
  },
  {
    id: 'CRIT-01-messages',
    name: 'CRIT-01 — messages sin RLS',
    node: 'TEST-CRIT01 — Leer messages',
    expectEmptyBody: true,
    severity: 'CRITICAL'
  },
  {
    id: 'bookings-isolation',
    name: 'Bookings — aislamiento entre usuarios',
    node: 'TEST — Leer todos bookings',
    expectOnlyOwnRows: true,
    uidField: 'client_id',
    severity: 'HIGH'
  },
  {
    id: 'payments-isolation',
    name: 'Payments — aislamiento entre usuarios',
    node: 'TEST — Leer todos payments',
    expectEmptyBody: true,
    severity: 'HIGH'
  },
  {
    id: 'contracts-isolation',
    name: 'Contratos — aislamiento entre usuarios',
    node: 'TEST — Leer contracts ajenos',
    expectEmptyBody: true,
    severity: 'HIGH'
  }
];

for (const check of checks) {
  let response;
  try {
    response = $node[check.node].json;
  } catch(e) {
    results.push({
      id: check.id,
      severity: check.severity,
      name: check.name,
      status: 'ERROR',
      detail: `No se pudo leer la respuesta del nodo: ${e.message}`
    });
    continue;
  }

  const body = response.body;
  const statusCode = response.statusCode;
  const rowCount = Array.isArray(body) ? body.length : 0;
  const attackerUid = $('Extraer JWT').item.json.ATTACKER_UID;

  if (check.expectEmptyBody) {
    // Si RLS funciona: array vacío o error 401/403
    if (statusCode >= 400 || rowCount === 0) {
      results.push({
        id: check.id,
        severity: check.severity,
        name: check.name,
        status: '✅ PASS',
        detail: `Status ${statusCode}, ${rowCount} filas devueltas. RLS bloqueó correctamente.`
      });
    } else {
      results.push({
        id: check.id,
        severity: check.severity,
        name: check.name,
        status: '❌ VULNERABLE',
        detail: `Status ${statusCode}, ${rowCount} filas expuestas a un usuario no autorizado. ACTIVAR RLS INMEDIATAMENTE.`,
        sample: Array.isArray(body) ? body.slice(0, 2) : body
      });
    }
  } else if (check.expectOnlyOwnRows) {
    // Filtra filas que NO pertenecen al atacante
    const foreignRows = Array.isArray(body)
      ? body.filter(row =>
          row.client_id !== attackerUid && row.owner_id !== attackerUid
        )
      : [];

    if (foreignRows.length === 0) {
      results.push({
        id: check.id,
        severity: check.severity,
        name: check.name,
        status: '✅ PASS',
        detail: `${rowCount} filas devueltas, todas pertenecen al usuario autenticado. RLS correcto.`
      });
    } else {
      results.push({
        id: check.id,
        severity: check.severity,
        name: check.name,
        status: '❌ VULNERABLE',
        detail: `${foreignRows.length} filas de OTROS usuarios expuestas de un total de ${rowCount}.`,
        foreignRows: foreignRows.slice(0, 3)
      });
    }
  }
}

// Resumen ejecutivo
const criticals  = results.filter(r => r.status.includes('VULNERABLE') && r.severity === 'CRITICAL').length;
const highs      = results.filter(r => r.status.includes('VULNERABLE') && r.severity === 'HIGH').length;
const passes     = results.filter(r => r.status.includes('PASS')).length;

const summary = {
  timestamp: new Date().toISOString(),
  total_checks: results.length,
  passed: passes,
  critical_failures: criticals,
  high_failures: highs,
  overall_status: criticals > 0 ? '🔴 CRÍTICO' : highs > 0 ? '🟠 ALTO' : '🟢 SEGURO',
  results
};

return [{ json: summary }];

const report = $input.item.json;

const lines = [
  `# 🚨 ALERTA CRÍTICA — ArtRider RLS Audit`,
  `Fecha: ${report.timestamp}`,
  ``,
  `## Resumen`,
  `- Total de checks: ${report.total_checks}`,
  `- ✅ Pasaron: ${report.passed}`,
  `- 🔴 Fallos CRÍTICOS: ${report.critical_failures}`,
  `- 🟠 Fallos ALTOS: ${report.high_failures}`,
  `- Estado general: ${report.overall_status}`,
  ``,
  `## Detalle de Vulnerabilidades Encontradas`,
];

for (const r of report.results) {
  if (r.status.includes('VULNERABLE')) {
    lines.push(`### [${r.severity}] ${r.name}`);
    lines.push(`**Estado:** ${r.status}`);
    lines.push(`**Detalle:** ${r.detail}`);
    if (r.sample) {
      lines.push(`**Muestra de datos expuestos:**`);
      lines.push('```json');
      lines.push(JSON.stringify(r.sample, null, 2));
      lines.push('```');
    }
    lines.push('');
  }
}

lines.push(`## Acción Requerida`);
lines.push(`Ejecutar la migración: \`art-rider/supabase/migrations/20260509_security_fixes.sql\``);
lines.push(`en el SQL Editor de Supabase **INMEDIATAMENTE**.');

return [{ json: { report_text: lines.join('\n'), ...report } }];

const report = $input.item.json;

const lines = [
  `# ✅ ArtRider RLS Audit — Sin vulnerabilidades críticas`,
  `Fecha: ${report.timestamp}`,
  ``,
  `## Resumen`,
  `- Total de checks: ${report.total_checks}`,
  `- ✅ Pasaron: ${report.passed}`,
  `- 🟠 Fallos altos: ${report.high_failures}`,
  `- Estado general: ${report.overall_status}`,
  ``,
];

if (report.high_failures > 0) {
  lines.push(`## Checks con advertencias`);
  for (const r of report.results) {
    if (r.status.includes('VULNERABLE')) {
      lines.push(`- **[${r.severity}] ${r.name}:** ${r.detail}`);
    }
  }
} else {
  lines.push(`Todos los checks de aislamiento de datos entre usuarios pasaron correctamente.`);
}

return [{ json: { report_text: lines.join('\n'), ...report } }];

// Nodo final: imprime el reporte en el log de n8n
// En producción: reemplazar con un nodo Slack / Email / PagerDuty
const item = $input.item.json;
console.log('=== ArtRider RLS Audit Report ===');
console.log(item.report_text || JSON.stringify(item, null, 2));
return [$input.item];
